/* Khuphela umxholo wefayile ye-tar kwilayibrari ye-libarchive. bool extract_archive(structure archive *src, const char *dest_path) {structure archive *out; structure_entry *entry; intrive flags = ARCHIVE_src_EXTRACT_TIME ARCHIVE_TRACT_PERM; intrive  */// Qalisa umbhali we-archive    out = archive_write_disk_new();
    if (!out) {
        return false;
    }
    archive_write_disk_set_options(out, flags);
// Funda uze ukhuphe ingxelo nganye    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // Yenza indlela epheleleyo        snprintf(full_path, sizeof(full_path), "%s/%s",
                dest_path, archive_entry_pathname(entry));
        archive_entry_set_pathname(entry, full_path);
// Bhala intloko        r = archive_write_header(out, entry);
        if (r != ARCHIVE_OK) {
            archive_write_free(out);
            return false;
        }
// Ukukhuphela idatha        const void *buff;
        size_t size;
        la_int64_t offset;
        while ((r = archive_read_data_block(src, &buff, &size, &offset)) == ARCHIVE_OK) {
            if (archive_write_data_block(out, buff, size, offset) != ARCHIVE_OK) {
                archive_write_free(out);
                return false;
            }
        }
        if (r != ARCHIVE_EOF) {
            archive_write_free(out);
            return false;
        }
    }

    archive_write_free(out);
    return r == ARCHIVE_EOF ? true : false;
}


